2. C++推理服务：
```cpp
// inference_server.cpp
#include <onnxruntime_cxx_api.h>
#include <opencv2/opencv.hpp>

class ImageClassifier {
public:
    ImageClassifier(const std::string& model_path) {
        Ort::SessionOptions session_options;
        session_options.SetIntraOpNumThreads(4);
        session_options.SetGraphOptimizationLevel(GraphOptimizationLevel::ORT_ENABLE_ALL);

        #ifdef USE_CUDA
        OrtCUDAProviderOptions cuda_options;
        session_options.AppendExecutionProvider_CUDA(cuda_options);
        #endif

        session_ = std::make_unique<Ort::Session>(env_, model_path.c_str(), session_options);
    }

    std::vector<float> Predict(const cv::Mat& image) {
        cv::Mat resized;
        cv::resize(image, resized, cv::Size(224, 224));

        std::vector<float> input_tensor_values(224 * 224 * 3);
        // 图像预处理：归一化、BGR->RGB

        Ort::MemoryInfo memory_info = Ort::MemoryInfo::CreateCpu(OrtArenaAllocator, OrtMemTypeDefault);
        Ort::Value input_tensor = Ort::Value::CreateTensor<float>(
            memory_info, input_tensor_values.data(), input_tensor_values.size(),
            input_shape_.data(), input_shape_.size());

        auto output_tensors = session_->Run(Ort::RunOptions{nullptr},
            input_names_.data(), &input_tensor, 1,
            output_names_.data(), 1);

        return std::vector<float>(output_tensors[0].GetTensorMutableData<float>(),
                                 output_tensors[0].GetTensorMutableData<float>()>() + 1000);
    }

private:
    Ort::Env env_;
    std::unique_ptr<Ort::Session> session_;
    std::vector<int64_t> input_shape_{1, 3, 224, 224};
};
```

3. RESTful API服务：
```cpp
// main.cpp
#include <cpprest/http_listener.h>
#include <cpprest/json.h>

using namespace web;
using namespace web::http;
using namespace web::http::experimental::listener;

class InferenceServer {
public:
    InferenceServer(const std::string& url, const std::string& model_path)
        : listener_(url), classifier_(model_path) {
        listener_.support(methods::POST, std::bind(&InferenceServer::HandlePost, this, std::placeholders::_1));
    }

    void HandlePost(http_request request) {
        try {
            auto json_value = request.extract_json().get();
            std::string image_base64 = json_value[U("image")].as_string();

            // Base64解码
            std::vector<uchar> decoded_data = base64_decode(image_base64);
            cv::Mat image = cv::imdecode(decoded_data, cv::IMREAD_COLOR);

            // 推理
            auto predictions = classifier_.Predict(image);

            // 获取top-5结果
            std::vector<int> top5_indices = GetTopK(predictions, 5);
            json::value response;

            for (size_t i = 0; i < top5_indices.size(); ++i) {
                json::value item;
                item[U("class_id")] = json::value::number(top5_indices[i]);
                item[U("confidence")] = json::value::number(predictions[top5_indices[i]]);
                item[U("label")] = json::value::string(class_labels_[top5_indices[i]]);
                response[i] = item;
            }

            request.reply(status_codes::OK, response);
        } catch (const std::exception& e) {
            json::value error;
            error[U("error")] = json::value::string(e.what());
            request.reply(status_codes::BadRequest, error);
        }
    }

private:
    http_listener listener_;
    ImageClassifier classifier_;
    std::vector<std::string> class_labels_;
};
```

