2. Jetson优化C++代码：
```cpp
// yolo_detector.cpp
#include <NvInfer.h>
#include <cuda_runtime.h>
#include <opencv2/opencv.hpp>

class YOLODetector {
public:
    YOLODetector(const std::string& engine_path) {
        runtime_ = nvinfer1::createInferRuntime(logger_);
        engine_ = runtime_->deserializeCudaEngine(engine_data_.data(), engine_data_.size());
        context_ = engine_->createExecutionContext();

        // Jetson Xavier NX优化
        context_->setOptimizationProfileAsync(0, stream_);
        cudaStreamCreate(&stream_);
    }

    std::vector<Detection> Detect(const cv::Mat& frame) {
        cv::Mat blob;
        cv::dnn::blobFromImage(frame, blob, 1/255.0, cv::Size(640, 640), cv::Scalar(0,0,0), true, false);

        // GPU内存优化
        void* buffers[2];
        cudaMalloc(&buffers[0], 1 * 3 * 640 * 640 * sizeof(float));
        cudaMalloc(&buffers[1], 1 * 84 * 8400 * sizeof(float));

        cudaMemcpyAsync(buffers[0], blob.ptr<float>(), \
                       1 * 3 * 640 * 640 * sizeof(float), \
                       cudaMemcpyHostToDevice, stream_);

        context_->enqueueV2(buffers, stream_, nullptr);

        // 后处理优化
        std::vector<float> output(84 * 8400);
        cudaMemcpyAsync(output.data(), buffers[1], \
                       84 * 8400 * sizeof(float), \
                       cudaMemcpyDeviceToHost, stream_);

        cudaStreamSynchronize(stream_);

        return PostProcess(output, frame.cols, frame.rows);
    }

private:
    nvinfer1::IRuntime* runtime_;
    nvinfer1::ICudaEngine* engine_;
    nvinfer1::IExecutionContext* context_;
    cudaStream_t stream_;
};
```

3. Jetson硬件优化：
```cpp
// jetson_optimization.h
#define JETSON_CLOCKS() \
    system("sudo nvpmodel -m 0"); \
    system("sudo jetson_clocks")

#define JETSON_POWER_MODE() \
    system("sudo nvpmodel -m 8")  // MAXN模式

// GPU内存池优化
class JetsonMemoryPool {
public:
    static void Initialize() {
        size_t free_byte, total_byte;
        cudaMemGetInfo(&free_byte, &total_byte);

        // 预留75%GPU内存
        size_t pool_size = (free_byte * 3) / 4;
        cudaMalloc(&gpu_pool_, pool_size);
        cudaMemset(gpu_pool_, 0, pool_size);
    }

private:
    static void* gpu_pool_;
};
```

4. 实时流水线：
```cpp
// real_time_pipeline.cpp
class RealTimePipeline {
public:
    void Run() {
        cv::VideoCapture cap(0);
        cap.set(cv::CAP_PROP_FRAME_WIDTH, 640);
        cap.set(cv::CAP_PROP_FRAME_HEIGHT, 480);
        cap.set(cv::CAP_PROP_FPS, 30);

        YOLODetector detector("yolov8n_int8.trt");

        while (true) {
            cv::Mat frame;
            cap >> frame;
            if (frame.empty()) break;

            auto start = std::chrono::high_resolution_clock::now();
            auto detections = detector.Detect(frame);
            auto end = std::chrono::high_resolution_clock::now();

            // 绘制结果
            for (const auto& det : detections) {
                cv::rectangle(frame, det.box, cv::Scalar(0, 255, 0), 2);
                cv::putText(frame, det.label, cv::Point(det.box.x, det.box.y - 5),
                           cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(0, 255, 0), 1);
            }

            // 性能显示
            double fps = 1000.0 / std::chrono::duration<double, std::milli>(end - start).count();
            cv::putText(frame, "FPS: " + std::to_string(fps), cv::Point(10, 30),
                       cv::FONT_HERSHEY_SIMPLEX, 1, cv::Scalar(0, 255, 0), 2);

            cv::imshow("YOLO Detection", frame);
            if (cv::waitKey(1) == 27) break;  // ESC退出
        }
    }
};
```

